protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 Cosmos: HasIndex now throws — Cosmos indexing is managed
    // via the container's indexing policy (Azure Portal / Bicep / Terraform).

    // EF Core 9 Cosmos: default discriminator property renamed from
    // "Discriminator" to "$type". Preserve "Discriminator" so existing
    // documents remain readable and raw SQL queries still work.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9 Cosmos: id no longer includes discriminator prefix.
    // Preserve "Blog|1" format so existing documents stay accessible.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);
}

